  options = '[{"id":"A","text":"The development of language is the result of the development of human civilization.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The development of human civilization has been made possible by the development of language.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The development of language and the development of human civilization are independent of each other.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The development of language and the development of human civilization are inextricably linked.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The passage explains that the development of language and the development of human civilization are intricately connected and are two facets of the same phenomenon.  The text specifically explains that as human civilization progressed, so did language.  The development of a new civilization led to a new language or a new version of an older language.  The text uses the development of Indo-European as an example of how language and civilization develop together.  The author concludes that the development of language and the development of human civilization are inextricably linked. The passage states that "The author of this passage explains the relationship between two seemingly unrelated concepts, the development of langua…", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: The development of language and the development of human civilization are inextricably linked.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":913,"opensat_domain":"Standard English Conventions","opensat_raw_id":"45672391","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.914Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
