  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":931,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_a5","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.914Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
